const body = $input.first().json.body || $input.first().json || {};

return {
  sessionId: body.session_id || ('sess_' + Date.now()),
  userMessage: body.user_message || '',
  messageHistory: Array.isArray(body.message_history) ? body.message_history : [],
  currentLead: body.current_lead || {},
  currentLeadCapture: body.current_lead_capture || {},
  lastProperties: Array.isArray(body.last_properties) ? body.last_properties : [],
  timestamp: new Date().toISOString()
};

const claudeRes = $input.first().json;
const ctx = $('Build Extraction Prompt').first().json;

const text = (claudeRes.content || [])
  .filter(function(c) { return c.type === 'text'; })
  .map(function(c) { return c.text; })
  .join('');

let raw = {};
try {
  const cleaned = text
    .replace(/```json\s*/gi, '')
    .replace(/```\s*/g, '')
    .trim();
  raw = JSON.parse(cleaned);
} catch(e) {
  raw = { needs_property_search: false, search_reason: 'json_parse_error_fallback' };
}

const cl = ctx.currentLead || {};
const clc = ctx.currentLeadCapture || {};

const criteria = {
  intent:                (raw.intent != null && raw.intent !== '') ? raw.intent : (cl.intent || null),
  city:                  (raw.city != null && raw.city !== '') ? raw.city : (cl.city || null),
  area:                  (raw.area != null && raw.area !== '') ? raw.area : null,
  budget_max:            (raw.budget_max != null && raw.budget_max > 0) ? raw.budget_max : (cl.budget || null),
  bedrooms_min:          (raw.bedrooms_min != null && raw.bedrooms_min > 0) ? raw.bedrooms_min : (cl.bedrooms != null ? cl.bedrooms : null),
  timeline:              (raw.timeline != null && raw.timeline !== '') ? raw.timeline : (cl.timeline || null),
  deal_type:             (raw.deal_type != null && raw.deal_type !== '') ? raw.deal_type : null,
  needs_property_search: raw.needs_property_search === true,
  search_reason:         raw.search_reason || ''
};

const name = (raw.customer_name != null && raw.customer_name !== '') ? raw.customer_name : (clc.name || null);
const phone = (raw.phone != null && raw.phone !== '') ? raw.phone : (clc.phone || null);
const email = (raw.email != null && raw.email !== '') ? raw.email : (clc.email || null);
const requested_action = (raw.requested_action != null && raw.requested_action !== '') ? raw.requested_action : (clc.requested_action || null);
const selected_property_reference = (raw.selected_property_reference != null && raw.selected_property_reference !== '') ? raw.selected_property_reference : (clc.selected_property_id || null);
const preferred_date_time = (raw.preferred_date_time != null && raw.preferred_date_time !== '') ? raw.preferred_date_time : (clc.preferred_date_time || null);

let capture_status = clc.capture_status || 'not_started';
if (requested_action === 'schedule_viewing') {
  if (!name || (!phone && !email)) {
    capture_status = 'waiting_for_contact';
  } else if (!preferred_date_time) {
    capture_status = 'waiting_for_time';
  } else {
    capture_status = 'contact_captured';
  }
} else if (requested_action === 'speak_to_agent' || requested_action === 'valuation_request') {
  if (!name || (!phone && !email)) {
    capture_status = 'waiting_for_contact';
  } else {
    capture_status = 'contact_captured';
  }
} else {
  if (name && (phone || email)) {
    capture_status = 'contact_captured';
  }
}

const hasContact = phone || email;
const isSeriousAction = requested_action === 'schedule_viewing' || requested_action === 'speak_to_agent' || requested_action === 'valuation_request';
const previouslySaved = clc.save_status === 'saved';
const should_save_lead = hasContact && isSeriousAction && !previouslySaved;

return {
  criteria:       criteria,
  leadCapture: {
    name: name,
    phone: phone,
    email: email,
    requested_action: requested_action,
    selected_property_id: selected_property_reference,
    preferred_date_time: preferred_date_time,
    capture_status: capture_status,
    should_save_lead: should_save_lead,
    save_status: clc.save_status || 'not_saved'
  },
  sessionId:      ctx.sessionId,
  userMessage:    ctx.userMessage,
  messageHistory: ctx.messageHistory,
  currentLead:    ctx.currentLead,
  currentLeadCapture: ctx.currentLeadCapture,
  timestamp:      ctx.timestamp
};

const rows = $input.all().map(function(i) { return i.json; });
const pd = $('Parse Extraction').first().json;
const c = pd.criteria;

function toNum(v) {
  if (v == null || v === '') return null;
  const x = parseFloat(String(v).replace(/[^0-9.-]/g, ''));
  return isNaN(x) ? null : x;
}

const filtered = rows.filter(function(r) {
  if (String(r.availability || '').toLowerCase().trim() !== 'available') return false;
  if (c.deal_type) {
    if (String(r.deal_type || '').toLowerCase().trim() !== c.deal_type.toLowerCase()) return false;
  }
  if (c.city) {
    const rc = String(r.city || '').toLowerCase();
    const cc = c.city.toLowerCase();
    if (!rc.includes(cc) && !cc.includes(rc)) return false;
  }
  if (c.area) {
    const ra = String(r.area || '').toLowerCase();
    if (!ra.includes(c.area.toLowerCase())) return false;
  }
  if (c.bedrooms_min != null) {
    const rb = toNum(r.bedrooms);
    if (rb == null || rb < Number(c.bedrooms_min)) return false;
  }
  if (c.budget_max != null) {
    const bgt = toNum(c.budget_max);
    if (bgt != null) {
      if (c.deal_type === 'rent') {
        const mp = toNum(r.price_per_month);
        if (mp != null && mp > bgt) return false;
      } else {
        const sp = toNum(r.price);
        if (sp != null && sp > bgt) return false;
      }
    }
  }
  return true;
});

const scored = filtered.map(function(r) {
  let s = 0;
  if (c.city && String(r.city || '').toLowerCase() === c.city.toLowerCase()) s += 10;
  if (c.area && String(r.area || '').toLowerCase().includes(c.area.toLowerCase())) s += 5;
  if (c.budget_max) {
    const bgt = toNum(c.budget_max);
    const price = c.deal_type === 'rent' ? toNum(r.price_per_month) : toNum(r.price);
    if (bgt && price != null && price <= bgt) s += Math.round((1 - price / bgt) * 5);
  }
  if (c.intent === 'invest') {
    const yld = toNum(r.investment_yield_pct);
    if (yld) s += Math.round(yld * 2);
  }
  return Object.assign({}, r, { _score: s });
});

const top3 = scored.sort(function(a, b) { return b._score - a._score; }).slice(0, 3);

const properties = top3.map(function(r) {
  return {
    property_id:          String(r.property_id || ''),
    title:                String(r.title || ''),
    deal_type:            String(r.deal_type || ''),
    city:                 String(r.city || ''),
    area:                 String(r.area || ''),
    price:                toNum(r.price),
    price_per_month:      toNum(r.price_per_month),
    currency:             String(r.currency || 'EUR'),
    bedrooms:             toNum(r.bedrooms) != null ? toNum(r.bedrooms) : 0,
    bathrooms:            toNum(r.bathrooms) != null ? toNum(r.bathrooms) : 0,
    size_sqm:             toNum(r.size_sqm) != null ? toNum(r.size_sqm) : 0,
    features:             String(r.features || ''),
    description:          String(r.description || ''),
    image_url:            String(r.image_url || ''),
    availability:         String(r.availability || ''),
    investment_yield_pct: toNum(r.investment_yield_pct)
  };
});

return {
  properties:      properties,
  propertiesFound: properties.length > 0,
  propertyCount:   properties.length,
  criteria:        pd.criteria,
  leadCapture:     pd.leadCapture,
  sessionId:       pd.sessionId,
  userMessage:     pd.userMessage,
  messageHistory:  pd.messageHistory,
  currentLead:     pd.currentLead,
  currentLeadCapture: pd.currentLeadCapture,
  timestamp:       pd.timestamp
};

const d = $input.first().json;
const props = d.properties || [];
const history = d.messageHistory || [];

const SYSTEM = 'You are Sofia, a professional AI Real Estate Sales Assistant for a European real estate agency.\n\nYour role is to help visitors who want to buy, rent, sell, or invest in property. Speak like a skilled, warm, consultative human sales assistant.\n\nRULES:\n- English only. Warm, professional, concise.\n- Ask maximum 2 questions per message.\n- Identify intent first, then build step by step: city, property type, budget, timeline.\n- If the visitor wants to book a viewing or speak to an agent, ask for their name and contact details (phone/email) if not already provided.\n- Thank them once provided, and ask for preferred date/time. Do not claim the viewing is fully confirmed - say the team will reach out to confirm.\n- NEVER invent property listings, prices, or availability.\n- ONLY recommend properties that appear in the PROPERTY CONTEXT provided in the user message.\n- If PROPERTY CONTEXT says no matches found, suggest adjusting criteria. Do not invent alternatives.\n- No legal, tax, mortgage or financial advice.\n- Keep replies short and conversational.';

function fmtProp(p) {
  const price = p.deal_type === 'rent'
    ? 'EUR ' + (p.price_per_month || 0) + '/month'
    : 'EUR ' + (p.price || 0).toLocaleString('en-EU');
  return '[' + p.property_id + '] ' + p.title
    + '\nLocation: ' + p.area + ', ' + p.city
    + ' | Price: ' + price
    + '\nBedrooms: ' + p.bedrooms + ' | Size: ' + p.size_sqm + 'm2'
    + '\nFeatures: ' + p.features
    + '\nDescription: ' + p.description;
}

const propContext = props.length > 0
  ? '[PROPERTY CONTEXT - START]\nFound matching properties in the database:\n\n'
    + props.map(fmtProp).join('\n\n---\n\n')
    + '\n[PROPERTY CONTEXT - END]\n\nYou may ONLY mention the properties listed above. Do not invent details.'
  : '[PROPERTY CONTEXT - START]\nNo properties matched the customer criteria.\n[PROPERTY CONTEXT - END]\n\nBe honest that no match was found. Suggest adjusting budget or location. Do NOT invent properties.';

const histWithoutLast = history.length > 0 ? history.slice(0, -1) : [];
const userMsgWithContext = d.userMessage + '\n\n' + propContext;

const reqBody = {
  model: 'claude-sonnet-4-5',
  max_tokens: 800,
  system: SYSTEM,
  messages: histWithoutLast.concat([{ role: 'user', content: userMsgWithContext }])
};

return {
  claudeRequestBody: JSON.stringify(reqBody),
  properties:        d.properties,
  propertiesFound:   d.propertiesFound,
  propertyCount:     d.propertyCount,
  criteria:          d.criteria,
  leadCapture:       d.leadCapture,
  sessionId:         d.sessionId,
  userMessage:       d.userMessage,
  messageHistory:    d.messageHistory,
  currentLead:       d.currentLead,
  currentLeadCapture: d.currentLeadCapture,
  timestamp:         d.timestamp
};

const d = $input.first().json;
const history = d.messageHistory || [];
const lastProps = $('Extract Variables').first().json.lastProperties || [];

const SYSTEM = 'You are Sofia, a professional AI Real Estate Sales Assistant for a European real estate agency.\n\nYour role is to help visitors who want to buy, rent, sell, or invest in property. Speak like a skilled, warm, consultative human sales assistant.\n\nRULES:\n- English only. Warm, professional, concise.\n- Ask maximum 2 questions per message.\n- Identify intent first, then build step by step: city, property type, budget, timeline.\n- If the visitor wants to book a viewing or speak to an agent, ask for their name and contact details (phone/email) if not already provided.\n- Thank them once provided, and ask for preferred date/time. Do not claim the viewing is fully confirmed - say the team will reach out to confirm.\n- NEVER invent property listings, prices, or availability.\n- No property search has run. Ask qualifying questions to gather missing criteria.\n- No legal, tax, mortgage or financial advice.\n- Keep replies short and conversational.';

function fmtProp(p) {
  const price = p.deal_type === 'rent'
    ? 'EUR ' + (p.price_per_month || 0) + '/month'
    : 'EUR ' + (p.price || 0).toLocaleString('en-EU');
  return '[' + p.property_id + '] ' + p.title
    + '\nLocation: ' + p.area + ', ' + p.city
    + ' | Price: ' + price
    + '\nBedrooms: ' + p.bedrooms + ' | Size: ' + p.size_sqm + 'm2\nFeatures: ' + p.features + '\nDescription: ' + p.description;
}

let messages = history;
if (lastProps.length > 0) {
  const propContext = '[LAST SHOWN PROPERTIES CONTEXT - START]\nThe customer was previously shown the following properties:\n\n'
    + lastProps.map(fmtProp).join('\n\n---\n\n')
    + '\n[LAST SHOWN PROPERTIES CONTEXT - END]\n\nYou can answer follow-up questions about these properties using only the details above. Do not show them as property cards again.';

  const histWithoutLast = history.length > 0 ? history.slice(0, -1) : [];
  messages = histWithoutLast.concat([{ role: 'user', content: d.userMessage + '\n\n' + propContext }]);
}

const reqBody = {
  model: 'claude-sonnet-4-5',
  max_tokens: 800,
  system: SYSTEM,
  messages: messages
};

return {
  claudeRequestBody: JSON.stringify(reqBody),
  properties:        [],
  propertiesFound:   false,
  propertyCount:     0,
  criteria:          d.criteria,
  leadCapture:       d.leadCapture,
  sessionId:         d.sessionId,
  userMessage:       d.userMessage,
  messageHistory:    d.messageHistory,
  currentLead:       d.currentLead,
  currentLeadCapture: d.currentLeadCapture,
  timestamp:         d.timestamp
};

