parameters.jsCode:
const claudeRes = $('Claude Generate Reply').first().json;
const md = $('Merge Paths').first().json;

// Determine if Google Sheets/Telegram save executed successfully
const savedNodeResult = $('IF Should Save Lead').first().json;
const hasBeenSaved = savedNodeResult.conditions?.save_lead_check === true || md.leadCapture.save_status === 'saved';

const text = (claudeRes.content || [])
  .filter(function(c) { return c.type === 'text'; })
  .map(function(c) { return c.text; })
  .join('');

const reply = text
  .replace(/\[PROPERTY CONTEXT - START\][\s\S]*?\[PROPERTY CONTEXT - END\]/g, '')
  .trim() || 'I apologize, I had a technical issue. Please try again.';

const cr = md.criteria || {};
const cl = md.currentLead || {};
const lc = md.leadCapture || {};

function calcScore(c, name, phone, email, action, time) {
  let s = 0;
  if (c.intent) s += 10;
  if (c.city) s += 10;
  if (c.budget_max) s += 10;
  if (c.bedrooms_min != null) s += 5;
  if (c.timeline) s += 10;
  if (name && (phone || email)) s += 30;
  if (action && action !== 'general_question') s += 15;
  if (time) s += 10;
  return Math.min(s, 100);
}

const ls = calcScore(cr, lc.name, lc.phone, lc.email, lc.requested_action, lc.preferred_date_time);
const lt = ls >= 70 ? 'hot' : ls >= 40 ? 'warm' : 'cold';

const lead = {
  intent:    cr.intent     || cl.intent     || null,
  city:      cr.city       || cl.city       || null,
  budget:    cr.budget_max || cl.budget     || null,
  bedrooms:  cr.bedrooms_min != null ? cr.bedrooms_min : (cl.bedrooms != null ? cl.bedrooms : null),
  timeline:  cr.timeline   || cl.timeline   || null,
  lead_score: ls,
  lead_tier:  lt
};

// Update status flags based on saves
let finalCaptureStatus = lc.capture_status;
let finalSaveStatus = lc.save_status;

if (hasBeenSaved) {
  finalSaveStatus = 'saved';
  finalCaptureStatus = 'notified'; // Trigger Notified on frontend visual display
}

const lead_capture = {
  name:                     lc.name,
  phone:                    lc.phone,
  email:                    lc.email,
  requested_action:         lc.requested_action,
  selected_property_id:     lc.selected_property_id,
  selected_property_title:  lc.selected_property_title || (md.properties && md.properties.length > 0 ? md.properties[0].title : null),
  preferred_date_time:      lc.preferred_date_time,
  capture_status:           finalCaptureStatus,
  save_status:              finalSaveStatus
};

const ts = new Date().toISOString();
const evts = [];

if (cr.intent) {
  evts.push({ type: 'intent_detected', label: 'Intent detected: ' + cr.intent.toUpperCase(), timestamp: ts });
}
if (cr.city) {
  evts.push({ type: 'lead_updated', label: 'City qualified: ' + cr.city, timestamp: ts });
}
if (lc.requested_action === 'schedule_viewing') {
  evts.push({ type: 'viewing_requested', label: 'Viewing request received', timestamp: ts });
}
if (lc.name && (lc.phone || lc.email)) {
  evts.push({ type: 'contact_captured', label: 'Contact captured for ' + lc.name, timestamp: ts });
}
if (hasBeenSaved) {
  evts.push({ type: 'lead_saved', label: 'Lead details logged in Google Sheets', timestamp: ts });
  evts.push({ type: 'sales_alert_sent', label: 'Hot lead Telegram notification sent to sales', timestamp: ts });
}
evts.push({ type: 'claude_response', label: 'Sofia response generated via Claude Sonnet', timestamp: ts });

return {
  session_id:    md.sessionId || 'unknown',
  timestamp:     md.timestamp || ts,
  reply:         reply,
  lead:          lead,
  lead_capture:  lead_capture,
  properties:    Array.isArray(md.properties) ? md.properties : [],
  system_events: evts
};
